# Find the quote starting with Arabic guillemet « and closing » if present or end of line/file.
start = text.find('«')
if start != -1:
    # end at the next » if exists; else end of string or newline? We'll capture until end of line.
    end_quote = text.find('»', start+1)
    if end_quote == -1:
        # no closing; end at end of string
        end = len(text)
    else:
        end = end_quote + 1
    hadith_span = (start, end, text[start:end])
else:
    hadith_span = None
hadith_span, text[start-60:start+100]
